          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_math_9_T9_1",
              "prompt": "Solve $dy/dx = (y + x)/x$ (homogeneous).",
              "steps": [
                "Substitute $y = vx$, $dy/dx = v + x\\,dv/dx$.",
                "Equation becomes: $v + x\\,dv/dx = v + 1$, so $x\\,dv/dx = 1$.",
                "Separate: $dv = dx/x$. Integrate: $v = \\ln|x| + C$.",
                "Back: $y/x = \\ln|x| + C$, so $y = x(\\ln|x| + C)$."
              ],
              "finalAnswer": "$y = x\\ln|x| + Cx$.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
